import React from "react";
import { Button } from "@mui/material";

export const SideBar = () => {
  return (
    <div className="grid grid-flow-row gap-2 mt-20">
      <Button>Home</Button>
      <Button>Solutions</Button>
      <Button>About</Button>
      <Button>Contact</Button>
    </div>
  );
};
